// 1. OLD — new Thread() manually. Almost never right in modern code.
Thread t = new Thread(() -> System.out.println("hi"));
t.start();

// 2. GOOD — ExecutorService (thread pool). Reuses threads for many tasks.
ExecutorService exec = Executors.newFixedThreadPool(4);
Future<Integer> f = exec.submit(() -> compute());
int result = f.get();       // blocks until done
exec.shutdown();

// 3. MODERN (Java 21+) — Virtual threads. Millions of them for I/O work.
try (var vexec = Executors.newVirtualThreadPerTaskExecutor()) {
    for (var req : requests) vexec.submit(() -> handle(req));
}
// Blocking code inside virtual threads unmounts from the carrier — no OS-thread waste.

// File: ConcurrencyDemo.java
// Compile: javac ConcurrencyDemo.java && java ConcurrencyDemo
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class ConcurrencyDemo {
  static int broken = 0;
  static volatile int volatileButBroken = 0;
  static AtomicInteger atomic = new AtomicInteger(0);
  static int synced = 0;
  static final Object lock = new Object();

  static void incrementSynchronized() {
    synchronized (lock) { synced++; }
  }

  public static void main(String[] args) throws Exception {
    final int threads = 8;
    final int perThread = 100_000;
    ExecutorService exec = Executors.newFixedThreadPool(threads);

    Runnable task = () -> {
      for (int i = 0; i < perThread; i++) {
        broken++;                              // RACE — some updates lost
        volatileButBroken++;                   // STILL race — increment isn't atomic
        atomic.incrementAndGet();              // safe — CAS
        incrementSynchronized();               // safe — mutex
      }
    };

    for (int i = 0; i < threads; i++) exec.submit(task);
    exec.shutdown();
    exec.awaitTermination(1, TimeUnit.MINUTES);

    int expected = threads * perThread;
    System.out.println("expected           : " + expected);
    System.out.println("broken (racy)      : " + broken            + "  (varies EVERY run)");
    System.out.println("volatile but racy  : " + volatileButBroken + "  (also varies!)");
    System.out.println("atomic (CAS)       : " + atomic.get()      + "  (always correct)");
    System.out.println("synchronized       : " + synced            + "  (always correct)");
  }
}

// Typical output:
//   expected           : 800000
//   broken (racy)      : 618341    (or any number below 800000)
//   volatile but racy  : 632587    (also wrong — volatile doesn't make ++ atomic!)
//   atomic (CAS)       : 800000
//   synchronized       : 800000
//
// Key lesson: volatile alone does NOT make read-modify-write safe.
